query:
SELECT rb.id as bundleId, rb.customerExternalId, rb.subscriberName, c.externalId, c.name
FROM retail_bundles rb
LEFT JOIN customers c ON rb.customerExternalId = c.externalId
WHERE rb.id = 133;

SELECT * FROM retail_bundle_cost_inputs WHERE bundleId = 133;

